INSERT INTO raw_emails (id, user_id, gmail_message_id, gmail_thread_id, subject, from_email, from_name, received_at, snippet, body_text) VALUES
  ('a0000001-0000-0000-0000-000000000001', :'demo_user_id', 'msg001', 'thread001', 'Application Received - Backend Engineer at Stripe', 'no-reply@stripe.com', 'Stripe Recruiting', '2026-03-28T09:15:00Z', 'Thank you for your application...', 'Dear Candidate, Thank you for applying to the Backend Engineer position at Stripe. We have received your application and our team will review it shortly.'),
  ('a0000001-0000-0000-0000-000000000002', :'demo_user_id', 'msg002', 'thread001', 'Interview Invitation - Stripe Backend Engineer', 'recruiting@stripe.com', 'Sarah Chen, Stripe', '2026-04-02T14:30:00Z', 'We would like to invite you...', 'Hi, We would like to invite you for a technical interview for the Backend Engineer role. The interview will be a 45-minute coding session.'),
  ('a0000001-0000-0000-0000-000000000003', :'demo_user_id', 'msg003', 'thread002', 'Your application to Google - Software Engineer', 'no-reply@google.com', 'Google Careers', '2026-03-15T11:00:00Z', 'Thank you for applying to Google...', 'Thank you for your interest in the Software Engineer position at Google. We are currently reviewing applications.'),
  ('a0000001-0000-0000-0000-000000000004', :'demo_user_id', 'msg004', 'thread003', 'Application Update - Frontend Developer at Shopify', 'notifications@shopify.com', 'Shopify Talent', '2026-04-01T08:45:00Z', 'We are moving forward with other candidates...', 'Thank you for your interest in the Frontend Developer role at Shopify. After careful review, we have decided to move forward with other candidates whose experience better aligns with our current needs.'),
  ('a0000001-0000-0000-0000-000000000005', :'demo_user_id', 'msg005', 'thread004', 'Grab - Online Assessment Link', 'assessment@grab.com', 'Grab University Recruiting', '2026-04-05T16:20:00Z', 'Please complete the online assessment...', 'Congratulations on progressing to the next stage! Please complete the online coding assessment within 48 hours. The assessment covers data structures and algorithms.'),
  ('a0000001-0000-0000-0000-000000000006', :'demo_user_id', 'msg006', 'thread005', 'Offer Letter - Shopee Backend Intern', 'hr@shopee.com', 'Shopee HR Team', '2026-04-10T10:00:00Z', 'We are pleased to offer you...', 'We are pleased to extend an offer for the Backend Intern position at Shopee. Please review the attached offer letter and respond by April 18, 2026.'),
  ('a0000001-0000-0000-0000-000000000007', :'demo_user_id', 'msg007', 'thread006', 'Application Received - Data Engineer at ByteDance', 'auto-reply@bytedance.com', 'ByteDance Recruitment', '2026-03-20T13:00:00Z', 'Your application has been received...', 'Thank you for applying to the Data Engineer position at ByteDance. We will review your application and get back to you within 2 weeks.'),
  ('a0000001-0000-0000-0000-000000000008', :'demo_user_id', 'msg008', 'thread007', 'Thank you for applying - TikTok Frontend Intern', 'careers@tiktok.com', 'TikTok Careers', '2026-04-03T09:30:00Z', 'We regret to inform you...', 'We regret to inform you that we will not be moving forward with your application for the Frontend Intern position at TikTok at this time.'),
  ('a0000001-0000-0000-0000-000000000009', :'demo_user_id', 'msg009', 'thread008', 'Interview Scheduled - Databricks Software Engineer', 'recruiting@databricks.com', 'Databricks Recruiting', '2026-04-08T11:15:00Z', 'Your interview is scheduled...', 'Your technical interview for the Software Engineer position at Databricks is scheduled for April 15, 2026 at 2:00 PM SGT. The interview will be conducted via Zoom.'),
  ('a0000001-0000-0000-0000-000000000010', :'demo_user_id', 'msg010', 'thread009', 'Application for Full Stack Engineer at Figma', 'jobs@figma.com', 'Figma Hiring', '2026-03-25T15:45:00Z', 'We received your application...', 'Thank you for your interest in the Full Stack Engineer role at Figma. We have received your application and will be in touch soon.'),
  ('a0000001-0000-0000-0000-000000000011', :'demo_user_id', 'msg011', 'thread010', 'Assessment Invitation - Infineon Software Engineer', 'campus@infineon.com', 'Infineon Campus Recruiting', '2026-04-06T10:30:00Z', 'You have been shortlisted for an assessment...', 'You have been shortlisted for the Software Engineer position at Infineon. Please complete the technical assessment by April 13, 2026.'),
  ('a0000001-0000-0000-0000-000000000012', :'demo_user_id', 'msg012', 'thread011', 'Your application to Amazon - SDE Intern', 'no-reply@amazon.jobs', 'Amazon University Programs', '2026-03-18T08:00:00Z', 'Application submitted successfully...', 'Your application for the Software Development Engineer Intern position at Amazon has been submitted successfully. Our team will review your application.'),
  ('a0000001-0000-0000-0000-000000000013', :'demo_user_id', 'msg013', 'thread012', 'Rejected - Microsoft Software Engineer', 'careers@microsoft.com', 'Microsoft Careers', '2026-04-07T17:00:00Z', 'We have decided to proceed with other candidates...', 'Thank you for interviewing with us for the Software Engineer position at Microsoft. After careful consideration, we have decided to proceed with other candidates.'),
  ('a0000001-0000-0000-0000-000000000014', :'demo_user_id', 'msg014', 'thread013', 'Application Update - NVIDIA Systems Engineer', 'recruiting@nvidia.com', 'NVIDIA Recruiting', '2026-04-09T14:00:00Z', 'Your application is under review...', 'Your application for the Systems Engineer position at NVIDIA is currently under review. We will update you on the next steps within 1-2 weeks.'),
  ('a0000001-0000-0000-0000-000000000015', :'demo_user_id', 'msg015', 'thread014', 'Next Steps - Meta Frontend Engineer', 'recruiting@meta.com', 'Meta Recruiting', '2026-04-11T09:00:00Z', 'We would like to schedule a call...', 'We have reviewed your application for the Frontend Engineer position at Meta and would like to schedule an initial phone screen. Please let us know your availability.');
